mapper.insert:
	/* Baim02Mapper.mergeCmmCodeDetailInfo */	
    INSERT INTO TB_BAIM_VAL_D (
    	CMPNY_CD
    	, BAIM_VAL_CD
    	, BAIM_VAL_D_CD
    	, BAIM_VAL_D_NM
    	, SORT_IDX
    	, USE_YN
    	, VAL_D_INFO_1
    	, VAL_D_INFO_2
    	, VAL_D_DESC
    	, INSERT_NO
    	, INSERT_DATE
    	, UPDATE_NO
    	, UPDATE_DATE
   	)
   	VALUES(
   		#{token.gv_cmpnyCd}
   		, #{param.baimValCd}
   		, IFNULL(#{param.baimValDCd}, FNC_CMM_SEQ_NEXTVAL(#{token.gv_cmpnyCd}, 'COM001'))
   		, #{param.baimValDNm}
   		, #{param.sortIdx}
		, #{param.useYn}
		, #{param.valDInfo1}
		, #{param.valDInfo2}
		, #{param.valDDesc}
		, #{token.gv_userId}
		, now()
		, #{token.gv_userId}
		, now() 
   	)
   	ON DUPLICATE KEY UPDATE
	    USE_YN     		= VALUES(USE_YN)
	    , BAIM_VAL_D_NM = VALUES(BAIM_VAL_D_NM)
	    , SORT_IDX		= VALUES(SORT_IDX)
	    , USE_YN		= IFNULL(USE_YN, 'Y')
	    , VAL_D_INFO_1	= VALUES(VAL_D_INFO_1)
    	, VAL_D_INFO_2	= VALUES(VAL_D_INFO_2)
    	, VAL_D_DESC	= VALUES(VAL_D_DESC)
	    , UPDATE_NO   	= #{token.gv_userId}
	    , UPDATE_DATE 	= NOW()

mapper.update:
/* Baim02Mapper.mergeCmmCodeDetailInfo */
UPDATE TB_BAIM_VAL_D 
SET USE_YN = 'N'
	, UPDATE_NO = #{token.gv_userId}
	, UPDATE_DATE = now()
WHERE CMPNY_CD = #{token.gv_cmpnyCd}
  AND BAIM_VAL_CD = #{param.baimValCd}
  AND BAIM_VAL_D_CD = #{param.baimValDCd}
